const listAgreements = `-- name: ListAgreements :many
SELECT
    a.id,
    a.tenant_id,
    a.agreement_type,
    a.title,
    a.template_id,
    t.name AS template_name,
    a.worker_profile_id,
    wp.display_name AS worker_display_name,
    wp.worker_code,
    a.engagement_id,
    e.title AS engagement_title,
    e.engagement_code,
    a.project_id,
    p.name AS project_name,
    p.project_code,
    a.subject,
    a.rendered_html,
    a.status,
    a.issue_date,
    a.effective_date,
    a.end_date,
    a.pdf_path,
    a.version,
    a.is_latest,
    a.sent_at,
    a.revoked_at,
    a.signature_token,
    a.signature_requested_at,
    a.signature_completed_at,
    a.signer_name,
    a.signer_email,
    a.signer_ip,
    a.signer_user_agent,
    a.signature_hash,
    a.audit_certificate_url,
    a.metadata,
    a.inactive,
    a.created_at,
    a.created_by,
    a.updated_at,
    a.updated_by
FROM hrms.agreements a
LEFT JOIN hrms.agreement_templates t ON t.tenant_id = a.tenant_id AND t.id = a.template_id AND NOT t.inactive
LEFT JOIN hrms.worker_profiles wp ON wp.tenant_id = a.tenant_id AND wp.id = a.worker_profile_id AND NOT wp.inactive
LEFT JOIN hrms.engagements e ON e.tenant_id = a.tenant_id AND e.id = a.engagement_id AND NOT e.inactive
LEFT JOIN hrms.projects p ON p.tenant_id = a.tenant_id AND p.id = a.project_id AND NOT p.inactive
WHERE a.tenant_id = $1
  AND ($2::text IS NULL OR a.agreement_type = $2::text)
  AND ($3::text IS NULL OR a.status = $3::text)
  AND ($4::uuid IS NULL OR a.worker_profile_id = $4::uuid)
  AND ($5::uuid IS NULL OR a.engagement_id = $5::uuid)
  AND ($6::uuid IS NULL OR a.project_id = $6::uuid)
  AND (
      $7::text IS NULL
      OR a.title ILIKE '%' || $7::text || '%'
      OR a.subject ILIKE '%' || $7::text || '%'
      OR wp.display_name ILIKE '%' || $7::text || '%'
      OR e.title ILIKE '%' || $7::text || '%'
      OR p.name ILIKE '%' || $7::text || '%'
  )
  AND NOT a.inactive
ORDER BY
    CASE a.status WHEN 'Generated' THEN 0 WHEN 'Approved' THEN 1 WHEN 'Sent' THEN 2 WHEN 'Signed' THEN 3 ELSE 4 END,
    a.updated_at DESC
`

