func (q *Queries) ListAgreements(ctx context.Context, arg ListAgreementsParams) ([]ListAgreementsRow, error) {
	rows, err := q.db.Query(ctx, listAgreements,
		arg.TenantID,
		arg.AgreementType,
		arg.Status,
		arg.WorkerProfileID,
		arg.EngagementID,
		arg.ProjectID,
		arg.Search,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListAgreementsRow
	for rows.Next() {
		var i ListAgreementsRow
		if err := rows.Scan(
			&i.ID,
			&i.TenantID,
			&i.AgreementType,
			&i.Title,
			&i.TemplateID,
			&i.TemplateName,
			&i.WorkerProfileID,
			&i.WorkerDisplayName,
			&i.WorkerCode,
			&i.EngagementID,
			&i.EngagementTitle,
			&i.EngagementCode,
			&i.ProjectID,
			&i.ProjectName,
			&i.ProjectCode,
			&i.Subject,
			&i.RenderedHtml,
			&i.Status,
			&i.IssueDate,
			&i.EffectiveDate,
			&i.EndDate,
			&i.PdfPath,
			&i.Version,
			&i.IsLatest,
			&i.SentAt,
			&i.RevokedAt,
			&i.SignatureToken,
			&i.SignatureRequestedAt,
			&i.SignatureCompletedAt,
			&i.SignerName,
			&i.SignerEmail,
			&i.SignerIp,
			&i.SignerUserAgent,
			&i.SignatureHash,
			&i.AuditCertificateUrl,
			&i.Metadata,
			&i.Inactive,
			&i.CreatedAt,
			&i.CreatedBy,
			&i.UpdatedAt,
			&i.UpdatedBy,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

